/**
 * Sentry Configuration
 * Error tracking and performance monitoring setup
 */

import * as Sentry from '@sentry/node';
import { nodeProfilingIntegration } from '@sentry/profiling-node';

/**
 * Initialize Sentry
 */
export function initSentry(): void {
  const dsn = process.env.SENTRY_DSN;
  const environment = process.env.NODE_ENV || 'development';
  const release = process.env.SENTRY_RELEASE || 'audira-gateway@unknown';

  // Skip initialization if DSN is not configured
  if (!dsn) {
    console.warn('Sentry DSN not configured. Error tracking disabled.');
    return;
  }

  Sentry.init({
    dsn,
    environment,
    release,

    // Performance Monitoring
    tracesSampleRate: environment === 'production' ? 0.1 : 1.0, // 10% in production, 100% in dev

    // Profiling
    profilesSampleRate: environment === 'production' ? 0.1 : 1.0,
    integrations: [
      nodeProfilingIntegration(),
    ],

    // Error filtering
    beforeSend(event, hint) {
      const error = hint.originalException;

      // Filter out specific errors
      if (error && typeof error === 'object' && 'code' in error) {
        // Don't send validation errors to Sentry
        if (error.code === 'VALIDATION_ERROR') {
          return null;
        }

        // Don't send authentication errors
        if (error.code === 'UNAUTHORIZED' || error.code === 'FORBIDDEN') {
          return null;
        }

        // Don't send rate limit errors
        if (error.code === 'RATE_LIMIT_EXCEEDED') {
          return null;
        }

        // Don't send 404 errors
        if (error.code === 'NOT_FOUND') {
          return null;
        }
      }

      return event;
    },

    // Ignore specific errors
    ignoreErrors: [
      'ECONNREFUSED',
      'ENOTFOUND',
      'ETIMEDOUT',
      'ESOCKETTIMEDOUT',
      'Token tidak valid',
      'Unauthorized',
    ],
  });

  console.log(`Sentry initialized for ${environment} environment`);
}

/**
 * Capture exception with context
 */
export function captureException(
  error: Error,
  context?: {
    user?: { id: string; username?: string; email?: string; role?: string };
    request?: { method: string; url: string; ip?: string };
    extra?: Record<string, any>;
    tags?: Record<string, string>;
    level?: Sentry.SeverityLevel;
  }
): string {
  return Sentry.captureException(error, {
    user: context?.user,
    contexts: {
      request: context?.request,
    },
    extra: context?.extra,
    tags: context?.tags,
    level: context?.level || 'error',
  });
}

/**
 * Capture message with context
 */
export function captureMessage(
  message: string,
  level: Sentry.SeverityLevel = 'info',
  context?: {
    user?: { id: string; username?: string; email?: string; role?: string };
    extra?: Record<string, any>;
    tags?: Record<string, string>;
  }
): string {
  return Sentry.captureMessage(message, {
    level,
    user: context?.user,
    extra: context?.extra,
    tags: context?.tags,
  });
}

/**
 * Set user context
 */
export function setUser(user: {
  id: string;
  username?: string;
  email?: string;
  role?: string;
}): void {
  Sentry.setUser(user);
}

/**
 * Clear user context
 */
export function clearUser(): void {
  Sentry.setUser(null);
}

/**
 * Add breadcrumb
 */
export function addBreadcrumb(
  message: string,
  category: string,
  level: Sentry.SeverityLevel = 'info',
  data?: Record<string, any>
): void {
  Sentry.addBreadcrumb({
    message,
    category,
    level,
    data,
    timestamp: Date.now() / 1000,
  });
}

/**
 * Set tag
 */
export function setTag(key: string, value: string): void {
  Sentry.setTag(key, value);
}

/**
 * Set context
 */
export function setContext(name: string, context: Record<string, any>): void {
  Sentry.setContext(name, context);
}

/**
 * Start span for performance monitoring
 */
export function startSpan<T>(
  name: string,
  op: string,
  callback: () => T | Promise<T>
): T | Promise<T> {
  return Sentry.startSpan(
    {
      name,
      op,
    },
    callback
  );
}

/**
 * Close Sentry client
 */
export async function closeSentry(): Promise<void> {
  await Sentry.close(2000);
}

