        tags: { feature: 'test' },
      };

      const eventId = captureMessage(message, 'warning', context);

      expect(Sentry.captureMessage).toHaveBeenCalledWith(
        message,
        expect.objectContaining({
          level: 'warning',
          user: context.user,
          extra: context.extra,
          tags: context.tags,
        })
      );
      expect(eventId).toBe('test-message-id');
    });

