      captureMessage(message);

      expect(Sentry.captureMessage).toHaveBeenCalledWith(
        message,
        expect.objectContaining({
          level: 'info',
        })
      );
    });
  });

  describe('setUser', () => {
    it('should set user context', () => {
      const user = {
        id: 'user-123',
        username: 'testuser',
        email: 'test@example.com',
        role: 'admin',
      };

      setUser(user);

      expect(Sentry.setUser).toHaveBeenCalledWith(user);
    });
  });

  describe('clearUser', () => {
    it('should clear user context', () => {
      clearUser();

      expect(Sentry.setUser).toHaveBeenCalledWith(null);
    });
  });

  describe('addBreadcrumb', () => {
    it('should add breadcrumb with all parameters', () => {
      const message = 'Test breadcrumb';
      const category = 'test';
      const level = 'info';
      const data = { key: 'value' };

      addBreadcrumb(message, category, level, data);

      expect(Sentry.addBreadcrumb).toHaveBeenCalledWith(
        expect.objectContaining({
          message,
          category,
          level,
          data,
          timestamp: expect.any(Number),
        })
      );
    });

    it('should use default info level', () => {
      const message = 'Test breadcrumb';
      const category = 'test';

      addBreadcrumb(message, category);

      expect(Sentry.addBreadcrumb).toHaveBeenCalledWith(
        expect.objectContaining({
          message,
          category,
          level: 'info',
        })
      );
    });
  });

  describe('setTag', () => {
    it('should set tag', () => {
      setTag('environment', 'test');

      expect(Sentry.setTag).toHaveBeenCalledWith('environment', 'test');
    });
  });

  describe('setContext', () => {
    it('should set context', () => {
      const context = { key: 'value' };

      setContext('custom', context);

      expect(Sentry.setContext).toHaveBeenCalledWith('custom', context);
    });
  });

  describe('startSpan', () => {
    it('should start span and execute callback', () => {
      const callback = vi.fn(() => 'result');

      const result = startSpan('test-operation', 'task', callback);

      expect(Sentry.startSpan).toHaveBeenCalledWith(
        expect.objectContaining({
          name: 'test-operation',
          op: 'task',
        }),
        callback
      );
      expect(result).toBe('result');
    });

    it('should handle async callbacks', async () => {
      const callback = vi.fn(async () => 'async-result');

      const result = await startSpan('async-operation', 'task', callback);

      expect(Sentry.startSpan).toHaveBeenCalled();
      expect(result).toBe('async-result');
    });
  });
});

